                if (new_cost < dp[ni][nj][rem_k]) {
                    dp[ni][nj][rem_k] = new_cost;
                    pq.emplace(new_cost, ni, nj, rem_k);
                }
            }
        }

        // Teleport move if remaining teleports > 0
        if (rem_k > 0) {
            for (int x = 0; x < m; ++x) {
