                        long long new_cost = cost;
                        if (new_cost < dp[x][y][rem_k - 1]) {
                            dp[x][y][rem_k - 1] = new_cost;
                            pq.emplace(new_cost, x, y, rem_k - 1);
                        }
                    }
                }
            }
        }
